#!/usr/bin/env node
// bin/cc-viewer.js — hand-authored ESM shim.
//
// NOT generated by tsc (the shebang would be stripped by the TS compiler).
// Committed directly to git so the shebang is guaranteed to ship intact.
// Delegates to the compiled CLI at packages/server/dist/cli.js.
// Verifiable post-publish via:
//   head -1 node_modules/cc-viewer/bin/cc-viewer.js
import { main } from '../packages/server/dist/cli.js'

main()
  .then((result) => {
    // main() resolves on successful server start with { code: 0, handle }.
    // The process stays alive after that because the Hono server keeps the
    // event loop busy; SIGINT/SIGTERM handlers (registered inside main())
    // call handle.close() and process.exit(0).
    //
    // If main() returned a non-zero exit code (arg error, port conflict),
    // exit immediately — no server was ever started.
    if (result.code !== 0) process.exit(result.code)
  })
  .catch((err) => {
    console.error(
      'cc-viewer: unexpected error:',
      err instanceof Error ? err.message : err,
    )
    process.exit(1)
  })
